<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Maze Bot Explorer</title>
    <style>
        body { 
            background: #1a1a1a; 
            color: #eee; 
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; 
            display: flex; 
            flex-direction: column; 
            align-items: center; 
            justify-content: center; 
            height: 100vh; 
            margin: 0; 
            overflow: hidden;
        }
        #ui-layer {
            display: flex;
            gap: 20px;
            margin-bottom: 15px;
            font-size: 1.2rem;
            font-weight: bold;
        }
        #maze {
            border: 4px solid #444;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            background: #000;
        }
        canvas { display: block; }
        .controls { margin-top: 20px; }
        button {
            padding: 10px 24px;
            font-size: 1rem;
            cursor: pointer;
            background: #3a86ff;
            border: none;
            color: white;
            border-radius: 4px;
            transition: background 0.2s;
        }
        button:hover { background: #2b6ed2; }
    </style>
</head>
<body>

    <div id="ui-layer">
        <div id="timer">Ticks: 0</div>
        <div id="completed">Completed: 0 / 24</div>
    </div>

    <div id="maze">
        <canvas id="gameCanvas"></canvas>
    </div>

    <div class="controls">
        <button id="reset">Reset Simulation</button>
    </div>

    <script>
        (function() {
            const canvas = document.getElementById('gameCanvas');
            const ctx = canvas.getContext('2d');
            const timerEl = document.getElementById('timer');
            const completedEl = document.getElementById('completed');
            const resetBtn = document.getElementById('reset');

            // Deterministic PRNG
            let currentSeed = 12345;
            function seededRandom() {
                currentSeed = (currentSeed * 9301 + 49297) % 233280;
                return currentSeed / 233280;
            }

            let mazeSeed = 0;
            let rows = 21;
            let cols = 21;
            let grid = [];
            let spawn = { r: 0, c: 0 };
            let exit = { r: 20, c: 20 };
            let bots = [];
            let elapsed = 0;

            function initMaze(seed) {
                mazeSeed = seed || Math.floor(Math.random() * 1000000);
                currentSeed = mazeSeed; // Reset LCG for deterministic generation
                const rng = () => {
                    currentSeed = (currentSeed * 9301 + 49297) % 233280;
                    return currentSeed / 233280;
                };

                grid = Array.from({ length: rows }, () => 
                    Array.from({ length: cols }, () => ({ walls: { n: true, e: true, s: true, w: true } }))
                );

                const stack = [[0, 0]];
                const visited = new Set(["0,0"]);
                visited.add("0,0");

                while (stack.length > 0) {
                    const [r, c] = stack[stack.length - 1];
                    const dirs = [
                        { dr: -1, dc: 0, wall: 'n', opp: 's' },
                        { dr: 1, dc: 0, wall: 's', opp: 'n' },
                        { dr: 0, dc: 1, wall: 'e', opp: 'w' },
                        { dr: 0, dc: -1, wall: 'w', opp: 'e' }
                    ].sort(() => rng() - 0.5);

                    let found = false;
                    for (let { dr, dc, wall, opp } of dirs) {
                        const nr = r + dr;
                        const nc = c + dc;
                        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited.has(`${nr},${nc}`)) {
                            grid[r][c].walls[wall] = false;
                            grid[nr][nc].walls[opp] = false;
                            visited.add(`${nr},${nc}`);
                            stack.push([nr, nc]);
                            found = true;
                            break;
                        }
                    }
                    if (!found) stack.pop();
                }

                spawn = { r: 0, c: 0 };
                exit = { r: rows - 1, c: cols - 1 };
            }

            function initBots() {
                bots = [];
                for (let i = 0; i < 24; i++) {
                    // Seeded preferences for each bot to ensure spread
                    const prefs = [0, 1, 2, 3].sort(() => seededRandom() - 0.5);
                    bots.push({
                        path: [{ r: spawn.r, c: spawn.c }],
                        visited: new Set([`${spawn.r},${spawn.c}`]),
                        deadEnds: [],
                        finishTick: null,
                        currentPos: { r: spawn.r, c: spawn.c },
                        targetPos: { r: spawn.r, c: spawn.c },
                        preferences: prefs,
                        color: `hsl(${i * 15}, 70%, 60%)`,
                        visualX: spawn.c * (canvas.width / cols),
                        visualY: spawn.r * (canvas.height / rows)
                    });
                }
            }

            function updateUI() {
                timerEl.innerText = `Ticks: ${elapsed}`;
                const completedCount = bots.filter(b => b.finishTick !== null).length;
                completedEl.innerText = `Completed: ${completedCount} / 24`;
            }

            window.game = {
                elapsed,
                size: { rows, cols },
                spawn,
                exit,
                walls: (r, c) => grid[r][c].walls,
                bots,
                tick: function(n) {
                    for (let i = 0; i < n; i++) {
                        let anyMoving = false;
                        for (let bot of bots) {
                            if (bot.finishTick !== null) continue;

                            let move = null;
                            // Tremaux/DFS Logic: Try forward to unvisited neighbor
                            for (let pIdx of bot.preferences) {
                                const dirMap = [[-1,0,'n','s'], [1,0,'s','n'], [0,1,'e','w'], [0,-1,'w','e']];
                                const [dr, dc, wall, opp] = dirMap[pIdx];
                                const nr = bot.currentPos.r + dr;
                                const nc = bot.currentPos.c + dc;

                                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && 
                                    !grid[bot.currentPos.r][bot.currentPos.c].walls[wall] &&
                                    !bot.visited.has(`${nr},${nc}`)) {
                                    move = { type: 'forward', pos: { r: nr, c: nc } };
                                    break;
                                }
                            }

                            // If no unvisited neighbors, backtrack to previous cell in path
                            if (!move && bot.path.length > 1) {
                                move = { type: 'backward', pos: bot.path[bot.path.length - 2] };
                            }

                            if (move) {
                                anyMoving = true;
                                if (move.type === 'forward') {
                                    bot.currentPos = move.pos;
                                    bot.path.push(move.pos);
                                    bot.visited.add(`${move.pos.r},${move.pos.c}`);
                                } else {
                                    // Pop the dead end from path and backtrack one step
                                    const deadEnd = bot.path.pop();
                                    bot.currentPos = move.pos;
                                    bot.deadEnds.push(deadEnd);
                                }
                                bot.targetPos = bot.currentPos;

                                if (bot.currentPos.r === exit.r && bot.currentPos.c === exit.c) {
                                    bot.finishTick = elapsed + 1;
                                }
                            }
                        }
                        if (anyMoving) elapsed++;
                    }
                    updateUI();
                },
                reset: function(seed) {
                    initMaze(seed);
                    initBots();
                    elapsed = 0;
                    updateUI();
                }
            };

            function setup() {
                const cellSize = 25;
                canvas.width = cols * cellSize;
                canvas.height = rows * cellSize;
                initMaze();
                initBots();
                elapsed = 0;
                updateUI();
            }

            // Animation Loop for smooth movement
            function animate() {
                ctx.clearRect(0, 0, canvas.width, canvas.height);
                const cellSize = canvas.width / cols;

                // Draw Maze Walls
                ctx.strokeStyle = '#555';
                ctx.lineWidth = 3;
                for (let r = 0; r < rows; r++) {
                    for (let c = 0; c < cols; c++) {
                        const w = grid[r][c].walls;
                        if (w.n) { ctx.beginPath(); ctx.moveTo(c * cellSize, r * cellSize); ctx.lineTo((c + 1) * cellSize, r * cellSize); ctx.stroke(); }
                        if (w.e) { ctx.beginPath(); ctx.moveTo((c + 1) * cellSize, r * cellSize); ctx.lineTo((c + 1) * cellSize, (r + 1) * cellSize); ctx.stroke(); }
                        if (w.s) { ctx.beginPath(); ctx.moveTo(c * cellSize, (r + 1) * cellSize); ctx.lineTo((c + 1) * cellSize, (r + 1) * cellSize); ctx.stroke(); }
                        if (w.w) { ctx.beginPath(); ctx.moveTo(c * cellSize, r * cellSize); ctx.lineTo(c * cellSize, (r + 1) * cellSize); ctx.stroke(); }
                    }
                }

                // Draw Bots with smooth interpolation
                bots.forEach(bot => {
                    const targetX = bot.targetPos.c * cellSize + cellSize / 2;
                    const targetY = bot.targetPos.r * cellSize + cellSize / 2;

                    // Smoothly interpolate visual position towards the current logical target
                    bot.visualX += (targetX - bot.visualX) * 0.15;
                    bot.visualY += (targetY - bot.visualY) * 0.15;

                    ctx.fillStyle = bot.color;
                    ctx.beginPath();
                    ctx.arc(bot.visualX, bot.visualY, cellSize / 4, 0, Math.PI * 2);
                    ctx.fill();
                    // Add a small glow/border to bots
                    ctx.strokeStyle = 'white';
                    ctx.lineWidth = 1;
                    ctx.stroke();
                });

                requestAnimationFrame(animate);
            }

            resetBtn.addEventListener('click', () => window.game.reset());

            setup();
            animate();
        })();
    </script>
</body>
</html>
